export const _userExercises: ExerciseWithTaxonomy[] = [];

export const allCatalogExercises: ExerciseWithTaxonomy[] = [
  ...exerciseCatalog,
  ..._additionalExercises,
  ..._finalExercises,
  ..._strongExercises,
  ..._userExercises,
];

const GENERATION_EXCLUDED_IDS = new Set(["chest-stretch", "hip-flexor-stretch"]);

export const generationCatalogExercises: ExerciseWithTaxonomy[] = exerciseCatalog.filter(
  (exercise) =>
    exercise.movementPattern !== "cardio" &&
    exercise.movementPattern !== "mobility" &&
    !GENERATION_EXCLUDED_IDS.has(exercise.id),
);
